import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';

class CircleMarker extends PureComponent {
  static propTypes = {
    id: PropTypes.number,
    text: PropTypes.string,
    selectedTargetId: PropTypes.number,
    style: PropTypes.object
  };

  render() {
    const {
      id,
      selectedTargetId,
      style,
      text
    } = this.props;

    const className = (id === selectedTargetId) ? 'marker-point__selected' : 'marker-point';

    return (
      <div id={`target-${id}`} style={style} className={className} >
        {text}
      </div>
    );
  }
}

export default CircleMarker;
