import React from 'react';

const CeoMGBase = ({
  id = 'ceo',
  className = 'mg-ceo-video',
  ariaLabel = 'Mensaje del CEO',
  videoSrc,
  posterSrc,
  onCanPlay,
  content
}) => (
  <section id={id} className={className} aria-label={ariaLabel}>
    <video autoPlay loop muted playsInline preload="auto" poster={posterSrc} onCanPlay={onCanPlay}>
      <source src={videoSrc} type="video/mp4" />
    </video>
    {content}
  </section>
);

export default CeoMGBase;
